import { 菩薩坐身, 上臂常勢, 前臂 } from './pusa.js';
import { 側拳, 臂釧, 腕釧 } from '../bujian/index.js';
export const 金剛拳尊 = (bi) => 菩薩坐身(bi, {
    臂(bi, 筆) {
        const { 骨, 細, 陰, 陽 } = 筆;
        骨(() => { 上臂常勢(筆, -1, 40.2); 上臂常勢(筆, 1, 40.2); });
        骨(() => 陽(() => 前臂(bi, 筆, [-13.7, 40.3], [-4.9, 37.1], { 寬根: 2.5, 寬梢: 1.9, 弓: -0.38, 肘帽: true })));
        骨(() => 陰(() => 前臂(bi, 筆, [13.7, 40.3], [4.9, 37.1], { 寬根: 2.5, 寬梢: 1.9, 弓: 0.38, 肘帽: true })));
        // 二拳並當胸（近而不觸，靜定之勢）
        側拳(bi, -3.0, 35.7, 0.44, 1.16);
        側拳(bi, 3.0, 35.7, -0.44, 1.16, -1);
        // 嚴
        臂釧(bi, -1, 12.1, 14.5, 33.4);
        臂釧(bi, 1, 12.1, 14.5, 33.4);
        細(() => {
            腕釧(bi, [[-5.9, 36.5, -5.3, 37.7, -4.5, 38.5], [-5.1, 36.1, -4.5, 37.3, -3.7, 38.1]], [-4.9, 37.4]);
            腕釧(bi, [[5.9, 36.5, 5.3, 37.7, 4.5, 38.5], [5.1, 36.1, 4.5, 37.3, 3.7, 38.1]], [4.9, 37.4]);
        });
    },
});
